solution_code:
#include <iostream>

class Holder {
    int m_val;
public:
    Holder(int v) : m_val{ v } {}

    void report() & {
        std::cout << "Named: " << m_val << "\n";
    }

    void report() && {
        std::cout << "Temp: " << m_val << "\n";
    }
};

int main() {
    int v;
    std::cin >> v;
    Holder h{ v };
    h.report();
    Holder{ v }.report();
    return 0;
}

