class Packet {
    int m_id;
public:
    Packet(int id) : m_id{ id } {}

    int id() const & { return m_id; }
    int id() && { return m_id + 1; }  // BUG: off by one
};

int main() {
    int n;
    std::cin >> n;
    Packet p{ n };
    std::cout << "Lvalue: " << p.id() << "\n";
    std::cout << "Rvalue: " << Packet{ n }.id() << "\n";
    return 0;
}

